import 'package:flutter/material.dart';
import 'package:flutter_html/flutter_html.dart';
import 'package:task_manager_flutter/data/services/checkout_caller.dart';
import 'package:html_unescape/html_unescape.dart';
import 'package:intl/intl.dart';
import 'package:task_manager_flutter/data/models/auth_utility.dart';
import 'package:task_manager_flutter/ui/widgets/negociacao_core.dart';
import 'package:task_manager_flutter/ui/widgets/envio_contrato_core.dart';
// file_upload_screen.dart
import 'package:flutter/material.dart';
import 'package:file_picker/file_picker.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';

class FileUploadScreen extends StatefulWidget {
  final SecurityCheck hasPermission;

  const FileUploadScreen({super.key, required this.hasPermission});

  @override
  _FileUploadScreenState createState() => _FileUploadScreenState();
}

class _FileUploadScreenState extends State<FileUploadScreen> {
  final _formKey = GlobalKey<FormState>();
  int? _diretorioId;
  int? _empresaId;
  PlatformFile? _selectedFile;
  bool _isUploading = false;

  final List<Map<String, dynamic>> _diretorios = [];
  final List<Map<String, dynamic>> _empresas = [];

  @override
  void initState() {
    super.initState();
    _loadDiretorios();
    _loadEmpresas();
  }

  Future<void> _loadDiretorios() async {
    final NetworkResponse response = await NetworkCaller().getRequest(
      ApiLinks.allDiretorios,
    );

    if (response.isSuccess && response.body != null) {
      final List<dynamic> data = response.body!['data']['dados'] ?? [];
      setState(() {
        _diretorios.clear();
        _diretorios.addAll(data
            .map((item) => {'value': item['id'], 'label': item['nome']})
            .toList());
      });
    }
  }

  Future<void> _loadEmpresas() async {
    final NetworkResponse response = await NetworkCaller().getRequest(
      ApiLinks.allEmpresas,
    );

    if (response.isSuccess && response.body != null) {
      final List<dynamic> data = response.body!['data']['dados'] ?? [];
      setState(() {
        _empresas.clear();
        _empresas.addAll(data
            .map((item) => {'value': item['id'], 'label': item['nome']})
            .toList());
      });
    }
  }

  Future<void> _selectFile() async {
    FilePickerResult? result = await FilePicker.platform.pickFiles();

    if (result != null) {
      setState(() {
        _selectedFile = result.files.first;
      });
    }
  }

  Future<void> _uploadFile() async {
    if (_selectedFile == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Selecione um arquivo primeiro')),
      );
      return;
    }

    setState(() {
      _isUploading = true;
    });

    try {
      final NetworkResponse response = await NetworkCaller().multipartRequest(
        ApiLinks.uploadArquivo,
        _selectedFile!.path!,
        'file',
        {
          'diretorioId': _diretorioId?.toString(),
          'empresaId': _empresaId?.toString(),
        },
      );

      if (response.isSuccess) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Arquivo enviado com sucesso!')),
        );
        Navigator.of(context).pop(true);
      } else {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Erro: ${response.errorMessage}')),
        );
      }
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Erro: $e')),
      );
    } finally {
      setState(() {
        _isUploading = false;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Upload de Arquivo'),
      ),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Form(
          key: _formKey,
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              DropdownButtonFormField<int>(
                value: _diretorioId,
                decoration: const InputDecoration(
                  labelText: 'Diretório',
                  border: OutlineInputBorder(),
                ),
                items: _diretorios.map((diretorio) {
                  return DropdownMenuItem<int>(
                    value: diretorio['value'],
                    child: Text(diretorio['label']),
                  );
                }).toList(),
                onChanged: (value) {
                  setState(() {
                    _diretorioId = value;
                  });
                },
                isExpanded: true,
              ),
              const SizedBox(height: 16),
              DropdownButtonFormField<int>(
                value: _empresaId,
                decoration: const InputDecoration(
                  labelText: 'Empresa',
                  border: OutlineInputBorder(),
                ),
                items: _empresas.map((empresa) {
                  return DropdownMenuItem<int>(
                    value: empresa['value'],
                    child: Text(empresa['label']),
                  );
                }).toList(),
                onChanged: (value) {
                  setState(() {
                    _empresaId = value;
                  });
                },
                isExpanded: true,
              ),
              const SizedBox(height: 16),
              OutlinedButton(
                onPressed: _selectFile,
                child: const Text('Selecionar Arquivo'),
              ),
              const SizedBox(height: 8),
              Text(
                _selectedFile != null
                    ? 'Arquivo selecionado: ${_selectedFile!.name}'
                    : 'Nenhum arquivo selecionado',
                textAlign: TextAlign.center,
              ),
              const SizedBox(height: 24),
              ElevatedButton(
                onPressed: _isUploading ? null : _uploadFile,
                child: _isUploading
                    ? const CircularProgressIndicator()
                    : const Text('Fazer Upload'),
              ),
            ],
          ),
        ),
      ),
    );
  }
}
